# Stepper Compound Component — Implementation Plan

## Context

Add a new `Stepper` compound component to the shadcn/ui `new-york-v4` registry. This is a multi-step progress indicator commonly used for wizards, onboarding flows, and checkout processes. It is a pure-React component (no Radix UI dependency) that uses React Context to share state across sub-components, following the same pattern as `carousel.tsx`.

---

## Critical Files

| Role | Path |
|------|------|
| **New** component | `apps/v4/registry/new-york-v4/ui/stepper.tsx` |
| **New** demo | `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx` |
| **Modify** UI registry | `apps/v4/registry/new-york-v4/ui/_registry.ts` |
| **Modify** examples registry | `apps/v4/registry/new-york-v4/examples/_registry.ts` |
| Utility (reuse) | `apps/v4/lib/utils.ts` → `cn()` |
| Reference pattern | `apps/v4/registry/new-york-v4/ui/carousel.tsx` |

---

## Step 1 — Create `ui/stepper.tsx`

**Full path:** `apps/v4/registry/new-york-v4/ui/stepper.tsx`

### Architecture
- Two React contexts:
  - `StepperContext` — shared by all descendants: `{ activeStep: number, orientation: "horizontal" | "vertical" }`
  - `StepperItemContext` — shared within a single step's subtree: `{ step: number, state: "completed" | "active" | "pending" }`
- Two internal hooks with error-boundary guards: `useStepper()` and `useStepperItem()`
- No external npm dependencies (pure React + Tailwind)

### Exact code structure

```tsx
"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

// ── Context types ────────────────────────────────────────────────────────────

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

type StepperItemContextProps = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)
const StepperItemContext = React.createContext<StepperItemContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ── Stepper (root) ────────────────────────────────────────────────────────────

function Stepper({
  orientation = "horizontal",
  activeStep,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  orientation?: "horizontal" | "vertical"
  activeStep: number
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-center" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ── StepperItem ───────────────────────────────────────────────────────────────

function StepperItem({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()
  const state: "completed" | "active" | "pending" =
    step < activeStep ? "completed" : step === activeStep ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn("flex items-center gap-2", className)}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ── StepperTrigger ────────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "active" && "border-primary text-primary",
        state === "pending" &&
          "border-muted-foreground/40 text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

// ── StepperTitle ──────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

// ── StepperDescription ────────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

// ── StepperSeparator ──────────────────────────────────────────────────────────
// Placed inside a StepperItem. Fills when that step's state is "completed"
// (i.e., the user has moved past it to the next step).

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "flex-1 bg-muted-foreground/30 transition-colors",
        state === "completed" && "bg-primary",
        orientation === "horizontal" ? "h-0.5" : "w-0.5 self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ── StepperContent ────────────────────────────────────────────────────────────

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn(className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ── Exports ───────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
```

### Key design decisions
- `StepperSeparator` uses **both** contexts: `useStepper()` for orientation, `useStepperItem()` for fill state. It is placed **inside** `<StepperItem>` as the last child of each non-final step. This is confirmed by the demo requirement: "Each step has a StepperTrigger, StepperTitle, and StepperSeparator."
- `state` derivation: `step < activeStep` → `"completed"`, `step === activeStep` → `"active"`, otherwise `"pending"`.
- Separator fills (`bg-primary`) when `state === "completed"` — meaning the user has advanced past that step, which is equivalent to "the NEXT step has been reached."
- `StepperContent` returns `null` when `step !== activeStep` (no hidden DOM node).
- No `export default` — named exports only, matching all other shadcn/ui components.

---

## Step 2 — Create `examples/stepper-demo.tsx`

**Full path:** `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`

```tsx
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="w-full max-w-xl space-y-6 p-4">
      <Stepper activeStep={activeStep}>
        <StepperItem step={1}>
          <StepperTrigger onClick={() => setActiveStep(1)} />
          <StepperTitle>Account</StepperTitle>
          <StepperSeparator />
        </StepperItem>
        <StepperItem step={2}>
          <StepperTrigger onClick={() => setActiveStep(2)} />
          <StepperTitle>Profile</StepperTitle>
          <StepperSeparator />
        </StepperItem>
        <StepperItem step={3}>
          <StepperTrigger onClick={() => setActiveStep(3)} />
          <StepperTitle>Complete</StepperTitle>
        </StepperItem>
      </Stepper>

      <StepperContent step={1}>
        <div className="rounded-lg border p-4">
          <p className="font-semibold">Account</p>
          <p className="text-sm text-muted-foreground">
            Set up your account credentials and preferences.
          </p>
        </div>
      </StepperContent>
      <StepperContent step={2}>
        <div className="rounded-lg border p-4">
          <p className="font-semibold">Profile</p>
          <p className="text-sm text-muted-foreground">
            Add your personal information and profile details.
          </p>
        </div>
      </StepperContent>
      <StepperContent step={3}>
        <div className="rounded-lg border p-4">
          <p className="font-semibold">Complete</p>
          <p className="text-sm text-muted-foreground">
            Your setup is complete. Welcome aboard!
          </p>
        </div>
      </StepperContent>

      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button
          onClick={() => setActiveStep((s) => Math.min(3, s + 1))}
          disabled={activeStep === 3}
        >
          Next
        </Button>
      </div>
    </div>
  )
}
```

### Key patterns
- `"use client"` at top (uses `React.useState`)
- Imports `Button` from `@/registry/new-york-v4/ui/button`
- Imports all Stepper components from `@/registry/new-york-v4/ui/stepper`
- `StepperContent` panels placed **outside** the `<Stepper>` (they only need `StepperContext`, not `StepperItemContext`)
- `export default` — demo files use default export (consistent with accordion-demo.tsx, drawer-demo.tsx, etc.)
- Step triggers are clickable (call `setActiveStep`) so user can jump to any step
- Prev/Next buttons are disabled at boundaries

---

## Step 3 — Add entry to `ui/_registry.ts`

**Insertion point:** After the `spinner` entry (ends at line 563), before the `switch` entry (starts at line 564). Alphabetical order: `spinner` < `stepper` < `switch`.

**No `dependencies` field** — pure React component, no npm packages needed.

```ts
  {
    name: "stepper",
    type: "registry:ui",
    files: [
      {
        path: "ui/stepper.tsx",
        type: "registry:ui",
      },
    ],
  },
```

Insert after the closing `},` of the `spinner` entry (line 563).

---

## Step 4 — Add entry to `examples/_registry.ts`

**Insertion point:** After the `spinner-item` entry (ends at line 2124), before the `switch-demo` entry (starts at line 2125). Alphabetical order: `spinner-item` < `stepper-demo` < `switch-demo`.

```ts
  {
    name: "stepper-demo",
    type: "registry:example",
    registryDependencies: ["stepper"],
    files: [
      {
        path: "examples/stepper-demo.tsx",
        type: "registry:example",
      },
    ],
  },
```

Insert after the closing `},` of the `spinner-item` entry (line 2124).

---

## Verification

1. **TypeScript compilation** — run `pnpm tsc --noEmit` in `apps/v4/` to catch any type errors in the new files.
2. **Visual check** — start the dev server (`pnpm dev` in `apps/v4/`) and navigate to the stepper demo page.
3. **Functional checks:**
   - Step 1 is active on load; trigger circle has `border-primary text-primary` styling
   - Click "Next" → step 1 becomes completed (filled circle + separator fills), step 2 becomes active
   - Click "Next" again → step 2 fills, step 3 becomes active; "Next" button disabled
   - Click "Previous" → reverses correctly; "Previous" button disabled at step 1
   - `StepperContent` panels swap correctly with each step
   - `data-slot`, `data-state`, `data-step`, `data-orientation` attributes present in DevTools
4. **Registry check** — verify `ui/_registry.ts` and `examples/_registry.ts` parse without errors (they're imported by the registry build system).

