"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile",
  },
  {
    step: 3,
    title: "Complete",
    description: "You're all set",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-xl flex-col gap-6">
      <Stepper activeStep={activeStep} className="w-full gap-2">
        {steps.map(({ step, title }, index) => (
          <React.Fragment key={step}>
            <StepperItem step={step} className="flex-col gap-2">
              <div className="flex items-center gap-2">
                <StepperTrigger onClick={() => setActiveStep(step)} />
                <div className="flex flex-col">
                  <StepperTitle>{title}</StepperTitle>
                </div>
              </div>
            </StepperItem>
            {index < steps.length - 1 && <StepperSeparator className="mx-2 mt-4" />}
          </React.Fragment>
        ))}
      </Stepper>

      {steps.map(({ step, title, description }) => (
        <StepperContent key={step} step={step} activeStep={activeStep}>
          <div className="rounded-lg border p-4">
            <h3 className="text-base font-semibold">{title}</h3>
            <p className="text-sm text-muted-foreground">{description}</p>
          </div>
        </StepperContent>
      ))}

      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((prev) => Math.max(1, prev - 1))}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button
          onClick={() =>
            setActiveStep((prev) => Math.min(steps.length, prev + 1))
          }
          disabled={activeStep === steps.length}
        >
          Next
        </Button>
      </div>
    </div>
  )
}

