import {
  Stepper,
  StepperContent,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account to get started.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile information.",
  },
  {
    step: 3,
    title: "Complete",
    description: "You're all done! Welcome aboard.",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-xl flex-col gap-6">
      <Stepper activeStep={activeStep} className="w-full">
        {steps.map(({ step, title }, index) => (
          <StepperItem key={step} step={step} className="flex-1 gap-2">
            <StepperTrigger onClick={() => setActiveStep(step)} />
            <StepperTitle>{title}</StepperTitle>
            {index < steps.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </Stepper>

      {steps.map(({ step, title, description }) => (
        <StepperContent key={step} step={step}>
          <div className="rounded-lg border p-4">
            <h3 className="text-base font-semibold">{title}</h3>
            <p className="mt-1 text-sm text-muted-foreground">{description}</p>
          </div>
        </StepperContent>
      ))}

      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((prev) => Math.max(1, prev - 1))}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button
          onClick={() =>
            setActiveStep((prev) => Math.min(steps.length, prev + 1))
          }
          disabled={activeStep === steps.length}
        >
          Next
        </Button>
      </div>
    </div>
  )
}

